/*
 * nn_openmp.c
 * Nearest Neighbor - OpenMP version
 *
 */

#include <stdio.h>
#include <sys/time.h>
#include <float.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define min( a, b )         ((a) > (b) ? (b) : (a))
#define ceilDiv( a, b )     ( (a) + (b) - 1 ) / (b)
#define DEBUG               0

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53
#define LATITUDE_POS 28
#define OPEN 10000

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

/* Dynamic arrays to replace std::vector */
typedef struct {
    Record *data;
    int size;
    int capacity;
} RecordVec;

typedef struct {
    LatLong *data;
    int size;
    int capacity;
} LatLongVec;

void RecordVec_init(RecordVec *v) {
    v->data = NULL;
    v->size = 0;
    v->capacity = 0;
}

void RecordVec_push(RecordVec *v, Record r) {
    if (v->size >= v->capacity) {
        v->capacity = v->capacity == 0 ? 16 : v->capacity * 2;
        v->data = (Record*)realloc(v->data, sizeof(Record) * v->capacity);
    }
    v->data[v->size++] = r;
}

void LatLongVec_init(LatLongVec *v) {
    v->data = NULL;
    v->size = 0;
    v->capacity = 0;
}

void LatLongVec_push(LatLongVec *v, LatLong l) {
    if (v->size >= v->capacity) {
        v->capacity = v->capacity == 0 ? 16 : v->capacity * 2;
        v->data = (LatLong*)realloc(v->data, sizeof(LatLong) * v->capacity);
    }
    v->data[v->size++] = l;
}

int loadData(char *filename, RecordVec *records, LatLongVec *locations);
void findLowest(RecordVec *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

/**
* Calculates the Euclidean distance from each record in the database to the target position
* Parallelized with OpenMP
*/
void euclid_openmp(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    int i;
    #pragma omp parallel for schedule(static)
    for (i = 0; i < numRecords; i++) {
        float dlat = lat - locations[i].lat;
        float dlng = lng - locations[i].lng;
        distances[i] = (float)sqrt(dlat * dlat + dlng * dlng);
    }
}

int main(int argc, char* argv[])
{
    int    i = 0;
    float lat, lng;
    int quiet = 0, timing = 0, platform = 0, device = 0;

    RecordVec records;
    LatLongVec locations;
    RecordVec_init(&records);
    LatLongVec_init(&locations);

    char filename[100];
    int resultsCount = 10;

    /* parse command line */
    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                     &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, &records, &locations);
    if (resultsCount > numRecords) resultsCount = numRecords;

    float *distances;
    distances = (float *)malloc(sizeof(float) * numRecords);

    struct timeval tv_kernel_start, tv_kernel_end;
    float kernel_time = 0.0f;

    gettimeofday(&tv_kernel_start, NULL);

    /* Execute parallel distance computation */
    euclid_openmp(locations.data, distances, numRecords, lat, lng);

    gettimeofday(&tv_kernel_end, NULL);

    {
        struct timeval tv_diff;
        tv_diff.tv_sec  = tv_kernel_end.tv_sec  - tv_kernel_start.tv_sec;
        tv_diff.tv_usec = tv_kernel_end.tv_usec - tv_kernel_start.tv_usec;
        if (tv_diff.tv_usec < 0) {
            tv_diff.tv_sec--;
            tv_diff.tv_usec += 1000000;
        }
        kernel_time = tv_diff.tv_sec * 1000.0f + (float)tv_diff.tv_usec / 1000.0f;
    }

    /* find the resultsCount least distances */
    findLowest(&records, distances, numRecords, resultsCount);

    /* print out results */
    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records.data[i].recString, records.data[i].distance);
        }

    if (timing)
        printf("Exec: %f\n", kernel_time);

    /* Print total time always to match expected output */
    printf("total time: %f ms\n", kernel_time);

    free(distances);
    free(records.data);
    free(locations.data);

    return 0;
}

int loadData(char *filename, RecordVec *records, LatLongVec *locations) {
    FILE   *flist, *fp;
    int    i = 0;
    char dbname[64];
    int recNum = 0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(1);
    }
    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if (!fp) {
            printf("error opening a db\n");
            exit(1);
        }
        /* read each record */
        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            fgets(record.recString, 49, fp);
            fgetc(fp); /* newline */
            if (feof(fp)) break;

            /* parse for lat and long */
            char substr[6];

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            LatLongVec_push(locations, latLong);
            RecordVec_push(records, record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(RecordVec *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }
        /* swap locations and distances */
        tempRec = records->data[i];
        records->data[i] = records->data[minLoc];
        records->data[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        /* add distance to the min we just found */
        records->data[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        *lat = atof(argv[i+1]);
                    } else {
                        *lng = atof(argv[i+1]);
                    }
                    i++;
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}
